  <div class="layout">
    <header class="header">
      <h1>Activity insights</h1>
      <p class="sub">Load Garmin <code>summarizedActivities</code> JSON, then ask questions in plain language (DuckDB + local AI).</p>
    </header>

    <section class="panel">
      <label class="file-label">
        <input type="file" id="file" accept=".json,application/json,text/plain" />
        <span>Choose summarized activities JSON</span>
      </label>
      <p id="data-status" class="status muted">No file loaded.</p>
      <div id="upload-progress-wrap" class="upload-progress-wrap" hidden>
        <progress id="upload-progress" max="100" value="0"></progress>
        <span id="upload-progress-label" class="upload-progress-label muted"></span>
        <div id="upload-progress-indeterminate" class="upload-progress-indeterminate" hidden></div>
      </div>
    </section>

    <section class="panel">
      <div class="row">
        <button type="button" id="btn-model" class="btn primary">Load AI model (Qwen2.5-Coder 1.5B)</button>
        <span id="model-status" class="status muted">Model not loaded.</span>
      </div>
      <p id="model-progress" class="progress muted"></p>
      <label class="inline-check">
        <input type="checkbox" id="chk-auto-model" />
        Auto-load model on next visit (uses browser cache; still takes a moment to initialize)
      </label>
    </section>

    <section class="panel">
      <label for="question">Question</label>
      <textarea id="question" rows="3" placeholder="e.g. What was my longest ride by distance last year?"></textarea>
      <div class="row">
        <button type="button" id="btn-ask" class="btn primary" disabled>Ask</button>
      </div>
    </section>

    <section class="panel thinking-panel" id="thinking-panel" hidden>
      <details id="thinking-details">
        <summary class="thinking-summary">Full prompt sent to model</summary>
        <textarea id="thinking" class="thinking-textarea" rows="6" readonly spellcheck="false"></textarea>
      </details>
    </section>

    <section class="panel">
      <label for="sql">Generated / manual SQL (DuckDB)</label>
      <textarea id="sql" rows="5" spellcheck="false"></textarea>
      <p id="timing-info" class="status muted" style="font-size:0.8em;margin-top:4px"></p>
      <div class="row">
        <button type="button" id="btn-run" class="btn" disabled>Run SELECT</button>
      </div>
    </section>

    <section class="panel">
      <h2>Results</h2>
      <div id="error" class="error" hidden></div>
      <div class="table-wrap">
        <table class="result-table">
          <thead id="thead"></thead>
          <tbody id="tbody"></tbody>
        </table>
      </div>
    </section>

    <footer class="footer">
      <button type="button" id="btn-clear" class="btn link">Clear saved activities from this browser</button>
    </footer>
  </div>
